module top_module(
  input clock,
  input reset,
  input [15:0] obf_In,
  input InEnable,
  output [15:0] Out
);reg [15:0]myRegIFToID;
  always@(posedge clock) begin

    if(reset)
      myRegIFToID = 0;
    else if(InEnable) myRegIFToID = obf_In; 
  end

  assign Out = myRegIFToID;
  endmodule
